import React, { useEffect, useState, useCallback } from "react";
import axios from "axios";
import { Card, Row, Col, Button, Table } from "react-bootstrap";
import { Pie } from "react-chartjs-2";
import { Chart as ChartJS, ArcElement, Tooltip, Legend } from "chart.js";
import { useLocation, useNavigate } from "react-router-dom";

ChartJS.register(ArcElement, Tooltip, Legend);

const ReconciliationDashboard = () => {
  const [stats, setStats] = useState({
    total: 0,
    matched: 0,
    partial: 0,
    duplicate: 0,
    unmatched: 0,
    accuracy: 0,
  });

  const [details, setDetails] = useState([]); // 🆕 holds each record
  const location = useLocation();
  const navigate = useNavigate();
  const jobId = new URLSearchParams(location.search).get("jobId");

  const fetchReconciliationSummary = useCallback(async () => {
    try {
      const token = localStorage.getItem("token");
      const url = jobId
        ? `http://localhost:4000/api/reconcile/summary?jobId=${jobId}`
        : `http://localhost:4000/api/reconcile/summary`;

      const res = await axios.get(url, {
        headers: { Authorization: `Bearer ${token}` },
      });

      if (res.data && res.data.length > 0) {
        calculateStats(res.data);
        setDetails(res.data); // 🆕 save all record data
      } else {
        setStats({
          total: 0,
          matched: 0,
          partial: 0,
          duplicate: 0,
          unmatched: 0,
          accuracy: 0,
        });
        setDetails([]);
      }
    } catch (err) {
      console.error("❌ Error fetching summary:", err);
    }
  }, [jobId]);

  const calculateStats = (data) => {
    const matched = data.filter((r) => r.status === "Matched").length;
    const partial = data.filter((r) => r.status === "Partially Matched").length;
    const duplicate = data.filter((r) => r.status === "Duplicate").length;
    const unmatched = data.filter((r) => r.status === "Unmatched").length;
    const total = data.length;
    const accuracy = total ? ((matched + partial * 0.5) / total) * 100 : 0;

    setStats({
      total,
      matched,
      partial,
      duplicate,
      unmatched,
      accuracy: accuracy.toFixed(2),
    });
  };

  useEffect(() => {
    fetchReconciliationSummary();
  }, [fetchReconciliationSummary]);

  const chartData = {
    labels: ["Matched", "Partial", "Duplicate", "Unmatched"],
    datasets: [
      {
        label: "Reconciliation Summary",
        data: [stats.matched, stats.partial, stats.duplicate, stats.unmatched],
        backgroundColor: ["#4CAF50", "#FFEB3B", "#9C27B0", "#F44336"],
      },
    ],
  };

  return (
    <div className="container mt-5">
      <div className="d-flex justify-content-between align-items-center">
        <h2>📊 Reconciliation Dashboard</h2>
        <Button
          variant="secondary"
          onClick={() => navigate("/history")}
          className="mb-2"
        >
          ⬅ Back to History
        </Button>
      </div>

      {/* Summary cards */}
      <Row className="mt-4">
        <Col md={2}>
          <Card className="p-3 text-center bg-primary text-white">
            <h5>Total</h5>
            <h3>{stats.total}</h3>
          </Card>
        </Col>
        <Col md={2}>
          <Card className="p-3 text-center bg-success text-white">
            <h5>Matched</h5>
            <h3>{stats.matched}</h3>
          </Card>
        </Col>
        <Col md={2}>
          <Card className="p-3 text-center bg-warning text-dark">
            <h5>Partial</h5>
            <h3>{stats.partial}</h3>
          </Card>
        </Col>
        <Col md={2}>
          <Card className="p-3 text-center bg-info text-white">
            <h5>Duplicate</h5>
            <h3>{stats.duplicate}</h3>
          </Card>
        </Col>
        <Col md={2}>
          <Card className="p-3 text-center bg-danger text-white">
            <h5>Unmatched</h5>
            <h3>{stats.unmatched}</h3>
          </Card>
        </Col>
        <Col md={2}>
          <Card className="p-3 text-center bg-secondary text-white">
            <h5>Accuracy (%)</h5>
            <h3>{stats.accuracy}</h3>
          </Card>
        </Col>
      </Row>

      {/* Pie chart */}
      <div className="mt-5 w-50 mx-auto">
        <Pie data={chartData} />
      </div>
<div className="text-center mt-4">
  <Button variant="dark" href="/reconciliation-view">
    🔍 View Detailed Records
  </Button>
</div>
      {/* 🆕 Detailed results table */}
      <div className="mt-5">
        <h4>📋 Reconciliation Details</h4>
        {details.length === 0 ? (
          <p>No reconciliation records found for this job.</p>
        ) : (
          <Table striped bordered hover responsive className="mt-3">
            <thead>
              <tr>
                <th>#</th>
                <th>Uploaded Record ID</th>
                <th>System Record ID</th>
                <th>Status</th>
                <th>Difference Details</th>
              </tr>
            </thead>
            <tbody>
              {details.map((row, idx) => (
                <tr key={idx}>
                  <td>{idx + 1}</td>
                  <td>{row.uploadedRecordId || "—"}</td>
                  <td>{row.systemRecordId || "—"}</td>
                  <td>
                    <span
                      className={`badge bg-${
                        row.status === "Matched"
                          ? "success"
                          : row.status === "Partially Matched"
                          ? "warning"
                          : row.status === "Duplicate"
                          ? "info"
                          : "danger"
                      }`}
                    >
                      {row.status}
                    </span>
                  </td>
                  <td>
                    {Object.keys(row.differences || {}).length > 0
                      ? JSON.stringify(row.differences)
                      : "—"}
                  </td>
                </tr>
              ))}
            </tbody>
          </Table>
        )}
      </div>
    </div>
  );
};

export default ReconciliationDashboard;
